/*! FocusLens Mini Charts - Chart.js compatible API subset */
(function(global){
'use strict';

const defaults = {
  color: '#6b6b85',
  borderColor: '#1c1c30',
  font: { family: "'Space Mono', monospace", size: 11 }
};

function resolveColor(c) {
  if (!c || c === 'transparent') return 'rgba(0,0,0,0)';
  return c;
}

function getCSSVar(name) {
  return getComputedStyle(document.documentElement).getPropertyValue(name).trim();
}

function formatVal(v) {
  if (v === undefined || v === null) return '';
  return String(v);
}

class Chart {
  constructor(ctx, config) {
    this.ctx = ctx;
    this.canvas = ctx.canvas;
    this.config = config;
    this.type = config.type;
    this.data = config.data;
    this.options = config.options || {};
    this._destroyed = false;
    this._tooltip = null;
    this._bindEvents();
    this._render();
  }

  destroy() {
    this._destroyed = true;
    this.canvas.removeEventListener('mousemove', this._onMove);
    this.canvas.removeEventListener('mouseleave', this._onLeave);
    const ctx = this.ctx;
    ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
  }

  _bindEvents() {
    this._onMove = (e) => { this._handleHover(e); };
    this._onLeave = () => { this._tooltip = null; this._render(); };
    this.canvas.addEventListener('mousemove', this._onMove);
    this.canvas.addEventListener('mouseleave', this._onLeave);
  }

  _handleHover(e) {
    const rect = this.canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    this._hoverX = x; this._hoverY = y;
    this._render();
  }

  _render() {
    if (this._destroyed) return;
    const canvas = this.canvas;
    const ctx = this.ctx;
    const dpr = window.devicePixelRatio || 1;

    // Size canvas properly
    const cssW = canvas.offsetWidth || canvas.width;
    const cssH = canvas.offsetHeight || canvas.height;
    if (canvas.width !== cssW * dpr || canvas.height !== cssH * dpr) {
      canvas.width = cssW * dpr;
      canvas.height = cssH * dpr;
      ctx.scale(dpr, dpr);
    }
    const W = cssW, H = cssH;

    ctx.clearRect(0, 0, W, H);

    if (this.type === 'bar') this._drawBar(ctx, W, H);
    else if (this.type === 'line') this._drawLine(ctx, W, H);
    else if (this.type === 'doughnut') this._drawDoughnut(ctx, W, H);
    else if (this.type === 'pie') this._drawPie(ctx, W, H);
  }

  _getFont(size) {
    const family = (this.options.font || defaults.font).family || defaults.font.family;
    return `${size || defaults.font.size}px ${family}`;
  }

  _getPadding(W, H, hasXLabels, hasYLabels, hasLegend) {
    return {
      top: 16,
      right: 16,
      bottom: hasXLabels ? 36 : 16,
      left: hasYLabels ? 52 : 16
    };
  }

  // ----------------------------------------------------------------
  // BAR CHART
  // ----------------------------------------------------------------
  _drawBar(ctx, W, H) {
    const ds = this.data.datasets[0];
    const labels = this.data.labels || [];
    const values = ds.data || [];
    const scales = (this.options.scales || {});
    const xScale = scales.x || {};
    const yScale = scales.y || {};

    const pad = { top: 16, right: 16, bottom: 40, left: 56 };
    const innerW = W - pad.left - pad.right;
    const innerH = H - pad.top - pad.bottom;

    const maxVal = Math.max(...values, 0.001);
    const yMax = this._niceMax(maxVal);
    const yTicks = this._niceTicksUp(yMax, yScale.maxTicksLimit || 5);

    // Grid lines + Y labels
    ctx.font = this._getFont(9);
    ctx.fillStyle = defaults.color;
    ctx.textAlign = 'right';
    yTicks.forEach(tv => {
      const yy = pad.top + innerH - (tv / yMax) * innerH;
      ctx.strokeStyle = 'rgba(255,255,255,0.04)';
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(pad.left, yy); ctx.lineTo(pad.left + innerW, yy); ctx.stroke();
      const label = yScale.ticks && yScale.ticks.callback ? yScale.ticks.callback(tv) : formatVal(tv);
      ctx.fillText(label, pad.left - 6, yy + 3);
    });

    // Bars
    const barCount = values.length;
    const barW = Math.max(4, (innerW / barCount) * 0.6);
    const gap = (innerW / barCount) * 0.4;

    values.forEach((v, i) => {
      const bh = (v / yMax) * innerH;
      const bx = pad.left + (i * innerW / barCount) + (innerW / barCount - barW) / 2;
      const by = pad.top + innerH - bh;

      const colors = ds.backgroundColor;
      ctx.fillStyle = resolveColor(Array.isArray(colors) ? colors[i] : colors) || 'rgba(124,58,237,0.6)';
      const radius = Math.min(ds.borderRadius || 4, bh / 2, barW / 2);
      this._roundRect(ctx, bx, by, barW, bh, radius, true, false);
    });

    // X labels
    const xTicks = xScale.ticks || {};
    const maxTicksX = xTicks.maxTicksLimit || labels.length;
    const step = Math.ceil(labels.length / maxTicksX);
    ctx.font = this._getFont(9);
    ctx.fillStyle = defaults.color;
    ctx.textAlign = 'center';
    labels.forEach((lbl, i) => {
      if (i % step !== 0) return;
      const lx = pad.left + (i * innerW / barCount) + (innerW / barCount) / 2;
      ctx.fillText(lbl, lx, H - pad.bottom + 16);
    });

    // Tooltip
    if (this._hoverX !== undefined) {
      const hx = this._hoverX;
      values.forEach((v, i) => {
        const bx = pad.left + (i * innerW / barCount) + (innerW / barCount - barW) / 2;
        if (hx >= bx - 4 && hx <= bx + barW + 4) {
          const label = this._getTooltipLabel(ds, v, i);
          const tx = bx + barW / 2;
          const ty = pad.top + innerH - (v / yMax) * innerH - 8;
          this._drawTooltip(ctx, tx, ty, labels[i] || '', label);
        }
      });
    }
  }

  // ----------------------------------------------------------------
  // LINE CHART
  // ----------------------------------------------------------------
  _drawLine(ctx, W, H) {
    const datasets = this.data.datasets || [];
    const labels = this.data.labels || [];
    const scales = this.options.scales || {};
    const yScale = scales.y || {};
    const pad = { top: 20, right: 20, bottom: 40, left: 56 };
    const innerW = W - pad.left - pad.right;
    const innerH = H - pad.top - pad.bottom;

    const allValues = datasets.flatMap(ds => ds.data || []);
    const yMin = yScale.min !== undefined ? yScale.min : Math.min(...allValues);
    const yMax = yScale.max !== undefined ? yScale.max : this._niceMax(Math.max(...allValues));
    const yRange = yMax - yMin || 1;
    const yTicks = this._niceTicksRange(yMin, yMax, yScale.maxTicksLimit || 5);

    // Grid + Y labels
    ctx.font = this._getFont(9);
    ctx.fillStyle = defaults.color;
    ctx.textAlign = 'right';
    yTicks.forEach(tv => {
      const yy = pad.top + innerH - ((tv - yMin) / yRange) * innerH;
      ctx.strokeStyle = 'rgba(255,255,255,0.04)';
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(pad.left, yy); ctx.lineTo(pad.left + innerW, yy); ctx.stroke();
      const lbl = yScale.ticks && yScale.ticks.callback ? yScale.ticks.callback(tv) : tv;
      ctx.fillText(lbl, pad.left - 6, yy + 3);
    });

    // X labels
    ctx.textAlign = 'center';
    labels.forEach((lbl, i) => {
      const lx = pad.left + (i / Math.max(labels.length - 1, 1)) * innerW;
      ctx.fillText(lbl, lx, H - pad.bottom + 16);
    });

    datasets.forEach(ds => {
      const pts = (ds.data || []).map((v, i) => ({
        x: pad.left + (i / Math.max(labels.length - 1, 1)) * innerW,
        y: pad.top + innerH - ((v - yMin) / yRange) * innerH
      }));
      if (pts.length < 2) return;

      const tension = ds.tension || 0;

      // Fill area
      if (ds.fill) {
        ctx.beginPath();
        this._drawCurve(ctx, pts, tension);
        ctx.lineTo(pts[pts.length - 1].x, pad.top + innerH);
        ctx.lineTo(pts[0].x, pad.top + innerH);
        ctx.closePath();
        ctx.fillStyle = resolveColor(ds.backgroundColor) || 'rgba(124,58,237,0.1)';
        ctx.fill();
      }

      // Line
      ctx.beginPath();
      this._drawCurve(ctx, pts, tension);
      ctx.strokeStyle = resolveColor(ds.borderColor) || '#7c3aed';
      ctx.lineWidth = ds.borderWidth || 2;
      ctx.stroke();

      // Points
      pts.forEach((p, i) => {
        const pr = ds.pointRadius || 4;
        const pbr = ds.pointBorderWidth || 2;
        ctx.beginPath();
        ctx.arc(p.x, p.y, pr, 0, Math.PI * 2);
        ctx.fillStyle = resolveColor(ds.pointBackgroundColor) || '#7c3aed';
        ctx.fill();
        ctx.strokeStyle = resolveColor(ds.pointBorderColor) || '#e8e8f5';
        ctx.lineWidth = pbr;
        ctx.stroke();
      });

      // Tooltip
      if (this._hoverX !== undefined) {
        pts.forEach((p, i) => {
          if (Math.abs(this._hoverX - p.x) < 20) {
            const lbl = this._getTooltipLabel(ds, ds.data[i], i);
            this._drawTooltip(ctx, p.x, p.y - 12, labels[i] || '', lbl);
          }
        });
      }
    });
  }

  _drawCurve(ctx, pts, tension) {
    ctx.moveTo(pts[0].x, pts[0].y);
    if (!tension) {
      pts.slice(1).forEach(p => ctx.lineTo(p.x, p.y));
      return;
    }
    for (let i = 0; i < pts.length - 1; i++) {
      const p0 = pts[i], p1 = pts[i + 1];
      const cpx = (p0.x + p1.x) / 2;
      ctx.bezierCurveTo(cpx, p0.y, cpx, p1.y, p1.x, p1.y);
    }
  }

  // ----------------------------------------------------------------
  // DOUGHNUT
  // ----------------------------------------------------------------
  _drawDoughnut(ctx, W, H) {
    this._drawPieBase(ctx, W, H, true);
  }

  _drawPie(ctx, W, H) {
    this._drawPieBase(ctx, W, H, false);
  }

  _drawPieBase(ctx, W, H, isDoughnut) {
    const ds = this.data.datasets[0];
    const labels = this.data.labels || [];
    const values = ds.data || [];
    const total = values.reduce((a, b) => a + b, 0) || 1;
    const cutout = isDoughnut ? (parseFloat(this.options.cutout) || 70) / 100 : 0;

    const legendOpts = (this.options.plugins || {}).legend || {};
    const showLegend = legendOpts.display !== false && !isDoughnut;
    const legendH = showLegend ? 40 : 0;

    const cx = W / 2;
    const cy = (H - legendH) / 2;
    const radius = Math.min(cx, cy) - 12;
    const innerR = radius * cutout;
    const spacing = isDoughnut ? (ds.spacing || 3) : 0;

    let startAngle = -Math.PI / 2;

    values.forEach((v, i) => {
      const slice = (v / total) * (Math.PI * 2);
      const endAngle = startAngle + slice - (spacing > 0 ? 0.02 : 0);
      const colors = ds.backgroundColor;
      const color = Array.isArray(colors) ? colors[i] : colors;

      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.arc(cx, cy, radius, startAngle, endAngle);
      ctx.closePath();
      ctx.fillStyle = resolveColor(color) || '#7c3aed';
      ctx.fill();

      if (isDoughnut) {
        // Cut out center
        ctx.beginPath();
        ctx.arc(cx, cy, innerR, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(0,0,0,0)';
        ctx.globalCompositeOperation = 'destination-out';
        ctx.fill();
        ctx.globalCompositeOperation = 'source-over';
      }

      startAngle += slice;
    });

    // Legend for pie
    if (showLegend && labels.length) {
      const lblColors = (legendOpts.labels || {});
      ctx.font = this._getFont(lblColors.font ? lblColors.font.size : 11);
      ctx.textAlign = 'center';
      const itemW = W / labels.length;
      labels.forEach((lbl, i) => {
        const lx = itemW * i + itemW / 2;
        const ly = H - legendH + 12;
        const colors = ds.backgroundColor;
        ctx.fillStyle = resolveColor(Array.isArray(colors) ? colors[i] : colors);
        ctx.fillRect(lx - 24, ly, 10, 10);
        ctx.fillStyle = lblColors.color || '#a0a0c0';
        ctx.fillText(lbl, lx + 4, ly + 9);
      });
    }

    // Tooltip
    if (this._hoverX !== undefined) {
      const dx = this._hoverX - cx, dy = this._hoverY - cy;
      const dist = Math.sqrt(dx*dx + dy*dy);
      if (dist <= radius && dist >= innerR) {
        let angle = Math.atan2(dy, dx) + Math.PI/2;
        if (angle < 0) angle += Math.PI * 2;
        let cumAngle = 0;
        for (let i = 0; i < values.length; i++) {
          const slice = (values[i] / total) * Math.PI * 2;
          if (angle >= cumAngle && angle < cumAngle + slice) {
            const cb = (this.options.plugins || {}).tooltip || {};
            const lbl = cb.callbacks && cb.callbacks.label
              ? cb.callbacks.label({ raw: values[i], label: labels[i], dataIndex: i })
              : `${labels[i] || ''}: ${values[i]}`;
            this._drawTooltip(ctx, this._hoverX, this._hoverY - 12, '', lbl);
            break;
          }
          cumAngle += slice;
        }
      }
    }
  }

  // ----------------------------------------------------------------
  // Helpers
  // ----------------------------------------------------------------
  _getTooltipLabel(ds, value, index) {
    const cb = ((this.options.plugins || {}).tooltip || {}).callbacks || {};
    if (cb.label) return cb.label({ raw: value, dataIndex: index, dataset: ds });
    return formatVal(value);
  }

  _drawTooltip(ctx, x, y, title, body) {
    const pad = 8;
    ctx.font = this._getFont(11);
    const titleW = ctx.measureText(title).width;
    const bodyW = ctx.measureText(body).width;
    const bw = Math.max(titleW, bodyW) + pad * 2;
    const bh = title ? 40 : 26;
    let tx = x - bw / 2;
    let ty = y - bh - 4;

    const canvas = this.canvas;
    if (tx < 4) tx = 4;
    if (tx + bw > canvas.offsetWidth - 4) tx = canvas.offsetWidth - bw - 4;
    if (ty < 4) ty = y + 12;

    ctx.save();
    ctx.fillStyle = 'rgba(12,12,20,0.92)';
    ctx.strokeStyle = '#2a2a45';
    ctx.lineWidth = 1;
    this._roundRect(ctx, tx, ty, bw, bh, 6, true, true);

    ctx.fillStyle = '#e8e8f5';
    if (title) {
      ctx.font = `bold ${this._getFont(11)}`;
      ctx.fillText(title, tx + pad, ty + 16);
      ctx.font = this._getFont(10);
      ctx.fillStyle = '#a0a0c0';
      ctx.fillText(body, tx + pad, ty + 30);
    } else {
      ctx.font = this._getFont(11);
      ctx.fillText(body, tx + pad, ty + 16);
    }
    ctx.restore();
  }

  _roundRect(ctx, x, y, w, h, r, fill, stroke) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
    if (fill) ctx.fill();
    if (stroke) ctx.stroke();
  }

  _niceMax(v) {
    if (v <= 0) return 1;
    const exp = Math.floor(Math.log10(v));
    const factor = Math.pow(10, exp);
    return Math.ceil(v / factor) * factor;
  }

  _niceTicksUp(max, count) {
    const step = max / (count - 1);
    const ticks = [];
    for (let i = 0; i <= count - 1; i++) ticks.push(Math.round(step * i));
    return ticks;
  }

  _niceTicksRange(min, max, count) {
    const range = max - min;
    const step = range / (count - 1);
    const ticks = [];
    for (let i = 0; i <= count - 1; i++) ticks.push(Math.round((min + step * i) * 10) / 10);
    return ticks;
  }
}

Chart.defaults = defaults;
Chart.register = () => {};  // no-op for compatibility

global.Chart = Chart;
})(typeof window !== 'undefined' ? window : this);
